def scatter_schemas(state: MessagesState, config: RunnableConfig) -> list[Send]:
    memory_types = config['configurable']['memory_types']
    sends = []

    for type in memory_types:
        match type:
            case "appointments":
                target = "update_appointments"
            case "conversations":
                target = "update_conversations"
